// --------------------------------------------------------------------------
// 1. BODY PART ITEM PATCH
// Injects the contamination component into harvested body parts and implants.
// Targets natural, bionic, royal, and imperial prosthetic bases.
// --------------------------------------------------------------------------

    Defs/ThingDef[@ParentName="BodyPartProstheticImperialBase" or @ParentName="BodyPartBionicImperialBase" or @ParentName="BodyPartRoyalBase" or @ParentName="BodyPartNaturalBase"]








