// 2. DISEASE TRANSMISSION PATCH (EXAMPLE: FLU)
// Marks the Flu as a disease capable of contaminating harvested organs.
// Configured to also infect artificial parts (bionics) for maximum lethality.
// --------------------------------------------------------------------------

    Defs/HediffDef[defName="Flu"]




                1.0
                true
                false
                true
